from handler import handle_with_retry, handle_batch, get_audit_trail
from processor import process_event
from store import clear, snapshot_state, restore_state, get_apply_log


def ingest(events, max_retries=3):
    """
    Robust ingest: for each event, attempt processing up to max_retries.
    On any exception we fully restore the store snapshot taken before the attempt,
    then retry. This guarantees no partial side-effects (including apply_log)
    remain from failed attempts.
    """
    clear()
    results = []

    for e in events:
        success = False
        last_exception = None
        for attempt in range(max_retries):
            snap = snapshot_state()
            try:
                val = process_event(e)
                results.append({"ok": True, "value": val, "attempt": attempt})
                success = True
                break
            except Exception as ex:
                # rollback to snapshot to remove any partial changes (including apply_log)
                restore_state(snap)
                last_exception = ex
                # continue to next attempt
        if not success:
            # All attempts failed; record failure for this event.
            results.append({"ok": False, "value": None})
            # continue processing remaining events (alternatively could abort)

    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
    # keep the old behavior for callers that explicitly want per-event handle_with_retry
    clear()
    results = []
    for e in events:
        results.append(handle_with_retry(e))
    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}"}

