    _records.clear()
    _apply_log.clear()


def snapshot_state():
    """Return a deep copy snapshot of the mutable store state."""
    return (copy.deepcopy(_records), copy.deepcopy(_apply_log))


def restore_state(snapshot):
    """Restore the store to a previously taken snapshot.

    snapshot should be a tuple (records_copy, apply_log_copy)
